import pytest
import base64

def test_message_with_phi_attachment_is_blocked_and_audit_logged(
    auth_session, api_base_url, known_provider_id, patient_subject_ref
):
    phi_content = base64.b64encode(b"Patient SSN: 123-45-6789").decode()
    payload = {
        "resourceType": "Communication",
        "status": "completed",
        "recipient": [{"reference": f"Practitioner/{known_provider_id}"}],
        "payload": [{
            "contentAttachment": {
                "contentType": "text/plain",
                "data": phi_content,
                "title": "notes.txt"
            }
        }]
    }
    resp = auth_session.post(f"{api_base_url}/messages", json=payload)
    assert resp.status_code in (403, 422), f"Expected block, got {resp.status_code}"

    error_body = resp.json()
    assert "phi" in str(error_body).lower() or "exfiltration" in str(error_body).lower()

    audit_resp = auth_session.get(
        f"{api_base_url}/AuditEvent",
        params={"agent": patient_subject_ref, "outcome:not": "0"}
    )
    assert audit_resp.status_code == 200
    entries = audit_resp.json().get("entry", [])
    assert len(entries) >= 1, "No failure AuditEvent found for blocked message"

import pytest
import base64

def test_message_attachment_at_maximum_allowed_size_accepted(
    auth_session, api_base_url, known_provider_id
):
    max_bytes = <get_max_attachment_bytes>(auth_session, api_base_url)
    clean_data = b"A" * max_bytes
    encoded = base64.b64encode(clean_data).decode()

    payload = {
        "resourceType": "Communication",
        "status": "completed",
        "recipient": [{"reference": f"Practitioner/{known_provider_id}"}],
        "payload": [{
            "contentAttachment": {
                "contentType": "application/octet-stream",
                "data": encoded,
                "title": "boundary_file.bin"
            }
        }]
    }
    resp = auth_session.post(f"{api_base_url}/messages", json=payload)
    assert resp.status_code == 201, f"Expected 201 at max boundary, got {resp.status_code}"

    message_id = resp.json()["id"]
    audit_resp = auth_session.get(
        f"{api_base_url}/AuditEvent",
        params={"entity": f"Communication/{message_id}"}
    )
    entries = audit_resp.json().get("entry", [])
    assert any(e["resource"].get("outcome") == "0" for e in entries), "No success AuditEvent"

import pytest
import time

def test_message_send_state_transitions_draft_to_notified_with_audit_chain(
    auth_session, api_base_url, known_provider_id
):
    create_payload = {
        "resourceType": "Communication",
        "status": "preparation",
        "recipient": [{"reference": f"Practitioner/{known_provider_id}"}],
        "payload": [{"contentString": "State transition test message"}]
    }
    r1 = auth_session.post(f"{api_base_url}/messages", json=create_payload)
    assert r1.status_code == 201
    msg_id = r1.json()["id"]

    r2 = auth_session.patch(
        f"{api_base_url}/messages/{msg_id}",
        json={"status": "in-progress"}
    )
    assert r2.status_code == 200

    r3 = auth_session.patch(
        f"{api_base_url}/messages/{msg_id}",
        json={"status": "completed"}
    )
    assert r3.status_code == 200

    final = <poll_until>(
        lambda: auth_session.get(f"{api_base_url}/messages/{msg_id}"),
        condition=lambda r: r.json().get("status") == "completed",
        timeout=10
    )
    assert final.json()["status"] == "completed"

    audit_resp = auth_session.get(
        f"{api_base_url}/AuditEvent",
        params={"entity": f"Communication/{msg_id}", "_sort": "date"}
    )
    entries = audit_resp.json().get("entry", [])
    assert len(entries) >= 3, f"Expected >=3 AuditEvents, got {len(entries)}"

import pytest
import base64

def test_message_exceeding_max_attachment_size_is_rejected(
    auth_session, api_base_url, known_provider_id, patient_subject_ref
):
    max_bytes = <get_max_attachment_bytes>(auth_session, api_base_url)
    oversized_data = b"B" * (max_bytes + 1)
    encoded = base64.b64encode(oversized_data).decode()

    payload = {
        "resourceType": "Communication",
        "status": "completed",
        "recipient": [{"reference": f"Practitioner/{known_provider_id}"}],
        "payload": [{
            "contentAttachment": {
                "contentType": "application/octet-stream",
                "data": encoded,
                "title": "oversized.bin"
            }
        }]
    }
    resp = auth_session.post(f"{api_base_url}/messages", json=payload)
    assert resp.status_code in (413, 422), f"Expected rejection, got {resp.status_code}"

    audit_resp = auth_session.get(
        f"{api_base_url}/AuditEvent",
        params={"agent": patient_subject_ref, "outcome:not": "0"}
    )
    entries = audit_resp.json().get("entry", [])
    assert len(entries) >= 1, "Expected a failure AuditEvent for oversized attachment"
